<?php/** * Enqueue and localize theme scripts and styles. * * @package optix */namespace Optix;if ( ! class_exists( 'OptixCore\Profile_Router' ) ) {	return;}/** * Move jQuery to footer */function move_jquery_into_footer( $wp_scripts ) {  if ( ! is_admin() ) {    $wp_scripts->add_data( 'jquery',         'group', 1 );    $wp_scripts->add_data( 'jquery-core',    'group', 1 );    $wp_scripts->add_data( 'jquery-migrate', 'group', 1 );  }} // end move_jquery_into_footer/** * Enqueue scripts and styles. *//** * Get profile asset base URI. */function profile_asset_uri( string $path = '' ): string {	$router  = \OptixCore\Profile_Router::get_instance();	$base_uri = get_template_directory_uri() . '/profiles/' . $router->get_active_profile() . '/assets';	if ( $path ) {		return $base_uri . '/' . ltrim( $path, '/' );	}	return $base_uri;}/** * Get profile asset base path (filesystem). */function profile_asset_path( string $path = '' ): string {	$router   = \OptixCore\Profile_Router::get_instance();	$base_path = get_template_directory() . '/profiles/' . $router->get_active_profile() . '/assets';	if ( $path ) {		return $base_path . '/' . ltrim( $path, '/' );	}	return $base_path;}function enqueue_theme_scripts() {  // Enqueue jquery  wp_enqueue_script( 'jquery' );  // Required comment-reply script  if ( is_singular() && comments_open() && get_option( 'thread_comments' ) ) {    wp_enqueue_script( 'comment-reply' );  }  // Detect if a WooCommerce page is active  $is_wc_page = function_exists( 'is_woocommerce' ) && ( is_woocommerce() || is_cart() || is_checkout() || is_account_page() );  // === KIDS COLLECTION ASSETS === //  // Bootstrap CSS  wp_enqueue_style( 'kc-bootstrap',    profile_asset_uri( 'css/bootstrap.min.css' ),    [],    '5.3.0'  );  // Font Awesome (with SRI integrity hash)  wp_enqueue_style( 'kc-fontawesome',    'https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css',    [],    '6.5.1'  );  wp_style_add_data( 'kc-fontawesome', 'integrity', 'sha384-DNOHZ68U8hZfKXOrtjWvjxusGo9WQnrNx2sqG0tfsghAvtVlRW3tvkXWZh58N9jp' );  wp_style_add_data( 'kc-fontawesome', 'crossorigin', 'anonymous' );  // Kids Collection main styles (after Bootstrap so it overrides)  wp_enqueue_style( 'kc-style',    profile_asset_uri( 'css/style.css' ),    [ 'kc-bootstrap' ],    filemtime( profile_asset_path( 'css/style.css' ) )  );  // Kids Collection responsive  wp_enqueue_style( 'kc-responsive',    profile_asset_uri( 'css/responsive.css' ),    [ 'kc-style' ],    filemtime( profile_asset_path( 'css/responsive.css' ) )  );  // Blog CSS (only on blog pages loaded via kids-collection)  $kc_page_slug = is_page() ? get_queried_object()->post_name : '';  if ( $kc_page_slug === 'blog' || $kc_page_slug === 'single-blog' || $kc_page_slug === 'load-more' ||       $kc_page_slug === 'one-column' || $kc_page_slug === 'two-column' || $kc_page_slug === 'three-column' ||       $kc_page_slug === 'three-column-sidebar' || $kc_page_slug === 'four-column' || $kc_page_slug === 'six-column-full-wide' ) {    $blog_css = profile_asset_path( 'css/blog.css' );    if ( file_exists( $blog_css ) ) {      wp_enqueue_style( 'kc-blog',        profile_asset_uri( 'css/blog.css' ),        [ 'kc-style' ],        filemtime( $blog_css )      );    }  }  // Shop CSS (on WooCommerce pages or hardcoded shop/cart/checkout template pages)  if ( $is_wc_page || in_array( $kc_page_slug, [ 'shop', 'cart', 'checkout', 'product-detail' ], true ) ) {    $shop_css = profile_asset_path( 'css/shop.css' );    if ( file_exists( $shop_css ) ) {      wp_enqueue_style( 'kc-shop',        profile_asset_uri( 'css/shop.css' ),        [ 'kc-style' ],        filemtime( $shop_css )      );    }    // WooCommerce theme overrides    $wc_css = profile_asset_path( 'css/woocommerce.css' );    if ( file_exists( $wc_css ) ) {      wp_enqueue_style( 'kc-woocommerce',        profile_asset_uri( 'css/woocommerce.css' ),        [ 'kc-shop' ],        filemtime( $wc_css )      );    }  }  // Google Fonts: only enqueue if a Google Font is selected  $kc_body_font    = optix_get_option( 'typography_body_font' );  $kc_heading_font = optix_get_option( 'typography_heading_font' );  $kc_needs_gfonts = ( $kc_body_font && 'System Default' !== $kc_body_font )    || ( $kc_heading_font && 'System Default' !== $kc_heading_font );  if ( $kc_needs_gfonts ) {    $kc_families = [];    if ( $kc_body_font && 'System Default' !== $kc_body_font ) {      $kc_families[] = str_replace( ' ', '+', $kc_body_font ) . ':wght@400;500;600;700';    }    if ( $kc_heading_font && 'System Default' !== $kc_heading_font ) {      $kc_families[] = str_replace( ' ', '+', $kc_heading_font ) . ':wght@400;500;600;700';    }    wp_enqueue_style( 'kc-google-fonts',      'https://fonts.googleapis.com/css2?family=' . implode( '&family=', $kc_families ) . '&display=swap',      [],      null    );  }  // Animate.css  $animate_css = profile_asset_path( 'css/animate.css' );  if ( file_exists( $animate_css ) ) {    wp_enqueue_style( 'kc-animate',      profile_asset_uri( 'css/animate.css' ),      [],      filemtime( $animate_css )    );  }  // Popper.js (with SRI)  wp_enqueue_script( 'kc-popper',    'https://cdn.jsdelivr.net/npm/@popperjs/core@2.11.8/dist/umd/popper.min.js',    [],    '2.11.8',    true  );  wp_script_add_data( 'kc-popper', 'integrity', 'sha384-PI7jBkC1eP5ZQr0SjHzGz2T4J1oFfgnQfe6Dk5dW+fZJRaSqRqLmVtOM9KgrwZ1' );  wp_script_add_data( 'kc-popper', 'crossorigin', 'anonymous' );  // Bootstrap JS  wp_enqueue_script( 'kc-bootstrap',    profile_asset_uri( 'js/bootstrap.min.js' ),    [ 'jquery', 'kc-popper' ],    filemtime( profile_asset_path( 'js/bootstrap.min.js' ) ),    true  );  // Magnific Popup CSS & JS (used by video-section.js)  $needs_magnific = $kc_page_slug === 'blog' || $kc_page_slug === 'single-blog';  if ( $needs_magnific || $is_wc_page ) {    wp_enqueue_style( 'kc-magnific-popup',      'https://cdnjs.cloudflare.com/ajax/libs/magnific-popup.js/1.1.0/magnific-popup.css',      [],      '1.1.0'    );    wp_style_add_data( 'kc-magnific-popup', 'integrity', 'sha384-aWjCoQWzMG6o+sx15PkZhgkV0dsuNvW7PBTwex1X3PXO3wIXrqU70AvBWfkQGK4E' );    wp_style_add_data( 'kc-magnific-popup', 'crossorigin', 'anonymous' );    wp_enqueue_script( 'kc-magnific-popup',      'https://cdnjs.cloudflare.com/ajax/libs/magnific-popup.js/1.1.0/jquery.magnific-popup.min.js',      [ 'jquery' ],      '1.1.0',      true    );    wp_script_add_data( 'kc-magnific-popup', 'integrity', 'sha384-fexNtx3nPE3sjIQuGk8G2X8X/aSEBVMC58R839hkgsY/Xjhvkm7m2otGhwrdESWj' );    wp_script_add_data( 'kc-magnific-popup', 'crossorigin', 'anonymous' );  }  // Determine if carousel assets are needed  $needs_carousel = false;  if ( is_singular() ) {    $post_content = get_post_field( 'post_content', get_queried_object_id() );    $needs_carousel = strpos( $post_content, 'owl-carousel' ) !== false;  }  $carousel_pages = [ 'front-page', 'about', 'shop', 'product-detail', 'testimonials', 'team', 'blog' ];  if ( ! $needs_carousel && in_array( $kc_page_slug, $carousel_pages, true ) ) {    $needs_carousel = true;  }  // Owl Carousel CSS (conditional)  if ( $needs_carousel ) {    $owl_css = profile_asset_path( 'css/owl.carousel.min.css' );    if ( file_exists( $owl_css ) ) {      wp_enqueue_style( 'kc-owl-carousel',        profile_asset_uri( 'css/owl.carousel.min.css' ),        [],        filemtime( $owl_css )      );    }    $owl_theme = profile_asset_path( 'css/owl.theme.default.min.css' );    if ( file_exists( $owl_theme ) ) {      wp_enqueue_style( 'kc-owl-theme',        profile_asset_uri( 'css/owl.theme.default.min.css' ),        [],        filemtime( $owl_theme )      );    }    $owl_js = profile_asset_path( 'js/owl.carousel.min.js' );    if ( file_exists( $owl_js ) ) {      wp_enqueue_script( 'kc-owl-carousel',        profile_asset_uri( 'js/owl.carousel.min.js' ),        [ 'jquery' ],        filemtime( $owl_js ),        true      );    }    $kc_carousel = profile_asset_path( 'js/carousel.js' );    if ( file_exists( $kc_carousel ) ) {      wp_enqueue_script( 'kc-carousel',        profile_asset_uri( 'js/carousel.js' ),        [ 'jquery', 'kc-owl-carousel' ],        filemtime( $kc_carousel ),        true      );    }  }  // WOW.js  $wow_js = profile_asset_path( 'js/wow.min.js' );  if ( file_exists( $wow_js ) ) {    wp_enqueue_script( 'kc-wow',      profile_asset_uri( 'js/wow.min.js' ),      [],      filemtime( $wow_js ),      true    );  }  // Contact form assets (only on contact page)  $is_contact_page = $kc_page_slug === 'contact';  if ( $is_contact_page ) {    $kc_validate = profile_asset_path( 'js/jquery.validate.js' );    if ( file_exists( $kc_validate ) ) {      wp_enqueue_script( 'kc-validate',        profile_asset_uri( 'js/jquery.validate.js' ),        [ 'jquery' ],        filemtime( $kc_validate ),        true      );    }    $kc_contact = profile_asset_path( 'js/contact-form.js' );    if ( file_exists( $kc_contact ) ) {      wp_enqueue_script( 'kc-contact-form',        profile_asset_uri( 'js/contact-form.js' ),        [ 'jquery', 'kc-validate' ],        filemtime( $kc_contact ),        true      );      wp_localize_script( 'kc-contact-form', 'OptixContact', [        'ajaxUrl' => admin_url( 'admin-ajax.php' ),        'nonce'   => wp_create_nonce( 'optix_contact_nonce' ),      ] );    }  }  // Counter / checkout tabs / coming-soon countdown (conditional)  $counter_pages = [ 'about', 'coming-soon', 'checkout', 'contact' ];  if ( in_array( $kc_page_slug, $counter_pages, true ) ) {    $kc_counter = profile_asset_path( 'js/counter.js' );    if ( file_exists( $kc_counter ) ) {      wp_enqueue_script( 'kc-counter',        profile_asset_uri( 'js/counter.js' ),        [ 'jquery' ],        filemtime( $kc_counter ),        true      );    }  }  // Blog load more (blog pages only)  if ( $kc_page_slug === 'blog' || $kc_page_slug === 'load-more' ) {    $kc_loadmore = profile_asset_path( 'js/loadmore.js' );    if ( file_exists( $kc_loadmore ) ) {      wp_enqueue_script( 'kc-loadmore',        profile_asset_uri( 'js/loadmore.js' ),        [ 'jquery' ],        filemtime( $kc_loadmore ),        true      );    }  }  // Kids Collection theme JS  $kc_js = profile_asset_path( 'js/theme.js' );  if ( file_exists( $kc_js ) ) {    wp_enqueue_script( 'kc-theme',      profile_asset_uri( 'js/theme.js' ),      [ 'jquery', 'kc-bootstrap', 'kc-wow' ],      filemtime( $kc_js ),      true    );  }  // Optix Extras JS (mega menu, 3D tilt)  $extras_js = profile_asset_path( 'js/optix-extras.js' );  if ( file_exists( $extras_js ) ) {    wp_enqueue_script( 'kc-extras',      profile_asset_uri( 'js/optix-extras.js' ),      [ 'jquery' ],      filemtime( $extras_js ),      true    );  }  // Portfolio archive/single CSS (enqueue on portfolio pages)  if ( is_post_type_archive( 'portfolio' ) || is_singular( 'portfolio' ) || is_tax( 'portfolio_category' ) ) {    $portfolio_css = profile_asset_path( 'css/style.css' );    if ( file_exists( $portfolio_css ) ) {      wp_enqueue_style( 'kc-portfolio',        profile_asset_uri( 'css/style.css' ),        [ 'kc-style' ],        filemtime( $portfolio_css )      );    }  }} // end enqueue_theme_scriptsadd_filter( 'style_loader_tag', function( $tag, $handle ) {    if ( 'kc-google-fonts' === $handle ) {        $tag = str_replace( '<link', '<link crossorigin="anonymous"', $tag );    }    return $tag;}, 10, 2 );